macroData.command:
// Get the data from Midi-QOL
const lastArg = args[args.length - 1];

// 1. Check if they failed the save at all
if (lastArg.failedSaves.length === 0) return; 

// 2. Get the target and the roll total
const target = canvas.tokens.get(lastArg.failedSaves[0].id);
const saveTotal = lastArg.saveRoll.total;
const dc = lastArg.item.system.save.dc;

// 3. Check if they failed by 5 or more
// (e.g. DC 13 - 5 = 8. If roll is 8 or lower, they sleep.)
if (saveTotal <= (dc - 5)) {
    // Apply "Unconscious" via Convenient Effects
    // If you don't use CE, change "Unconscious" to the exact name of the effect in your sidebar
    if (game.dfreds && game.dfreds.effectInterface) {
         await game.dfreds.effectInterface.addEffect({
            effectName: "Unconscious", 
            uuid: target.actor.uuid,
            origin: lastArg.item.uuid
        });
    } else {
        // Fallback for non-CE users: Toggle the overlay manually or via token API
        target.toggleEffect("icons/svg/unconscious.svg", {overlay: true});
    }

    // Send a message to chat so everyone knows why they dropped
    ChatMessage.create({
        content: `<b>${target.name}</b> failed by 5 or more! The Drow poison knocks them unconscious.`
    });
}
